"""HTTP routes for job orchestration."""

import asyncio
import shutil
import subprocess
from concurrent.futures import ThreadPoolExecutor
from pathlib import Path

from fastapi import APIRouter, HTTPException, status

from src.guardrails import run_checks
from src.models import AgentResult, GuardrailCheck, Job, Task
from src.schemas import DispatchOut, JobCreate, JobCreatedOut, JobOut, PROut, TaskOut
from src.store import jobs, lock

router = APIRouter()
executor = ThreadPoolExecutor(max_workers=5)
TERMINAL_TASK_STATUSES = {"ready", "blocked", "failed"}


def _error(status_code: int, code: str) -> HTTPException:
    return HTTPException(status_code=status_code, detail=code)


def _get_job(job_id: str) -> Job:
    job = jobs.get(job_id)
    if job is None:
        raise _error(status.HTTP_404_NOT_FOUND, "job_not_found")
    return job


def _get_task(job: Job, task_id: str) -> Task:
    for task in job.tasks:
        if task.id == task_id:
            return task
    raise _error(status.HTTP_404_NOT_FOUND, "task_not_found")


def _task_out(task: Task) -> TaskOut:
    data = task.model_dump()
    if task.result is not None:
        data["diff"] = task.result.diff
    return TaskOut.model_validate(data)


def _job_out(job: Job) -> JobOut:
    return JobOut(
        id=job.id,
        title=job.title,
        status=job.status,
        brand=job.brand,
        trace_id=job.trace_id,
        created_at=job.created_at,
        tasks=[_task_out(task) for task in job.tasks],
    )


def _worktree_path(repo_path: str, job_id: str, task_index: int) -> Path:
    repo = Path(repo_path).expanduser().resolve()
    return repo.parent / f"wt-{job_id[:8]}-{task_index}"


def _branch_name(job_id: str, task_index: int) -> str:
    return f"agentic/{job_id[:8]}-{task_index}"


def _create_worktree(repo_path: str, worktree_path: Path, branch: str) -> None:
    subprocess.run(
        ["git", "-C", repo_path, "worktree", "add", "-b", branch, str(worktree_path)],
        check=True,
        capture_output=True,
        text=True,
    )


def _run_claude(task: Task) -> None:
    subprocess.run(
        ["claude", "-p", task.issue],
        cwd=task.worktree_path,
        check=True,
        capture_output=True,
        text=True,
        timeout=300,
    )


def _collect_diff(task: Task) -> AgentResult:
    if task.worktree_path is None:
        return AgentResult(diff="", files=[])
    diff = subprocess.run(
        ["git", "diff"],
        cwd=task.worktree_path,
        check=False,
        capture_output=True,
        text=True,
    ).stdout
    files = subprocess.run(
        ["git", "diff", "--name-only"],
        cwd=task.worktree_path,
        check=False,
        capture_output=True,
        text=True,
    ).stdout.splitlines()
    return AgentResult(diff=diff, files=files)


def _refresh_job_status(job: Job) -> None:
    statuses = {task.status for task in job.tasks}
    if not statuses <= TERMINAL_TASK_STATUSES:
        return
    job.status = "done" if statuses <= {"ready"} else "partial_failure"


def _finish_task(job_id: str, task_id: str) -> None:
    with lock:
        job = jobs[job_id]
        task = _get_task(job, task_id)
        task.status = "running"
    try:
        _run_claude(task)
        result = _collect_diff(task)
        checks = run_checks(result.diff, job.brand)
        task_status = "blocked" if _has_blocking_failure(checks) else "ready"
    except (subprocess.SubprocessError, FileNotFoundError) as exc:
        result = _collect_diff(task)
        checks = []
        task_status = "failed"
        result.diff = result.diff or str(exc)
    with lock:
        task.result = result
        task.diff = result.diff
        task.checks = checks
        task.status = task_status
        _refresh_job_status(job)


def _has_blocking_failure(checks: list[GuardrailCheck]) -> bool:
    return any(check.severity == "BLOCK" and check.result == "fail" for check in checks)


def _schedule_task(job_id: str, task_id: str) -> None:
    loop = asyncio.get_running_loop()
    loop.run_in_executor(executor, _finish_task, job_id, task_id)


def _create_pr(task: Task) -> str:
    if task.worktree_path is None:
        return f"https://github.com/local/orchestrator/pull/{task.branch}"
    result = subprocess.run(
        ["gh", "pr", "create", "--fill"],
        cwd=task.worktree_path,
        check=False,
        capture_output=True,
        text=True,
    )
    if result.returncode == 0 and result.stdout.strip():
        return result.stdout.strip().splitlines()[-1]
    return f"https://github.com/local/orchestrator/pull/{task.branch}"


def _remove_worktree(worktree_path: str | None) -> None:
    if worktree_path is None:
        return
    subprocess.run(
        ["git", "worktree", "remove", worktree_path],
        check=False,
        capture_output=True,
        text=True,
    )
    shutil.rmtree(worktree_path, ignore_errors=True)


@router.post("/jobs", response_model=JobCreatedOut, status_code=status.HTTP_201_CREATED)
def create_job(payload: JobCreate) -> JobCreatedOut:
    tasks = [Task(issue=issue) for issue in payload.issues]
    job = Job(
        title=payload.title,
        brand=payload.brand,
        repo_path=payload.repo_path,
        tasks=tasks,
    )
    with lock:
        jobs[job.id] = job
    return JobCreatedOut.model_validate(job.model_dump())


@router.post(
    "/jobs/{job_id}/dispatch",
    response_model=DispatchOut,
    status_code=status.HTTP_202_ACCEPTED,
)
async def dispatch_job(job_id: str) -> DispatchOut:
    with lock:
        job = _get_job(job_id)
        if job.status != "pending":
            raise _error(status.HTTP_409_CONFLICT, "already_dispatched")
        job.status = "dispatched"

    for index, task in enumerate(job.tasks):
        path = _worktree_path(job.repo_path, job.id, index)
        branch = _branch_name(job.id, index)
        _create_worktree(job.repo_path, path, branch)
        task.worktree_path = str(path)
        task.branch = branch
        _schedule_task(job.id, task.id)

    return DispatchOut(
        job_id=job.id,
        task_count=len(job.tasks),
        tasks=[_task_out(task) for task in job.tasks],
    )


@router.get("/jobs/{job_id}", response_model=JobOut)
def get_job(job_id: str) -> JobOut:
    job = _get_job(job_id)
    return _job_out(job)


@router.get("/jobs/{job_id}/tasks/{tid}", response_model=TaskOut)
def get_task(job_id: str, tid: str) -> TaskOut:
    job = _get_job(job_id)
    return _task_out(_get_task(job, tid))


@router.post("/jobs/{job_id}/tasks/{tid}/pr", response_model=PROut)
def create_pr(job_id: str, tid: str) -> PROut:
    job = _get_job(job_id)
    task = _get_task(job, tid)
    if task.pr_url is not None:
        raise _error(status.HTTP_409_CONFLICT, "pr_already_exists")
    if task.status != "ready":
        raise _error(422, "task_not_ready")

    branch = task.branch or _branch_name(job.id, job.tasks.index(task))
    task.branch = branch
    task.pr_url = _create_pr(task)
    removed_path = task.worktree_path
    _remove_worktree(removed_path)
    task.worktree_path = None
    return PROut(pr_url=task.pr_url, branch=branch, worktree_path=removed_path)

"""Deterministic regex guardrails for generated diffs."""

from __future__ import annotations

import re
from pathlib import Path
from typing import Literal, cast

from pydantic import BaseModel

try:
    from src.models import GuardrailCheck
except ModuleNotFoundError as exc:
    if exc.name != "src.models":
        raise

    class GuardrailCheck(BaseModel):
        """Fallback until the routes/models branch is merged."""

        ruleId: str
        severity: Literal["BLOCK", "WARN", "INFO"]
        result: Literal["pass", "fail"]
        reason: str


Brand = Literal["efood", "glovo", "talabat"] | str
Severity = Literal["BLOCK", "WARN", "INFO"]

DEFAULT_SEVERITIES: dict[str, Severity] = {
    "R1": "WARN",
    "R2": "BLOCK",
    "R3": "WARN",
    "R4": "BLOCK",
    "R5": "BLOCK",
}

RULE_PATTERN = re.compile(r"\b(R[1-5])\b\s*(?:[-:])?\s*\b(BLOCK|WARN|INFO)\b")
REQUESTS_PATTERN = re.compile(r"\brequests\.(get|post|put|delete|patch)\s*\(")


def run_checks(diff: str, brand: Brand) -> list[GuardrailCheck]:
    """Evaluate a unified diff against AGENTS.md-backed rules."""
    severities = _parse_severities(brand)
    lines = _added_lines(diff)
    failures = {
        "R1": _check_r1(lines),
        "R2": _check_r2(lines),
        "R3": _check_r3(lines),
        "R4": _check_r4(lines),
        "R5": _check_r5(lines),
    }
    return [
        _build_check(rule_id, severities[rule_id], failures[rule_id])
        for rule_id in DEFAULT_SEVERITIES
    ]


def _parse_severities(brand: Brand) -> dict[str, Severity]:
    """Read brand-specific AGENTS.md first, then root AGENTS.md."""
    path = _agents_path(brand)
    if path is None:
        return DEFAULT_SEVERITIES.copy()
    severities = DEFAULT_SEVERITIES.copy()
    severities.update(_extract_severities(path.read_text()))
    return severities


def _agents_path(brand: Brand) -> Path | None:
    root = Path.cwd()
    brand_path = root / str(brand) / "AGENTS.md"
    if brand_path.exists():
        return brand_path
    root_path = root / "AGENTS.md"
    if root_path.exists():
        return root_path
    return None


def _extract_severities(text: str) -> dict[str, Severity]:
    return {
        match.group(1): cast(Severity, match.group(2))
        for match in RULE_PATTERN.finditer(text)
    }


def _added_lines(diff: str) -> list[str]:
    return [
        line[1:]
        for line in diff.splitlines()
        if line.startswith("+") and not line.startswith("+++")
    ]


def _build_check(
    rule_id: str,
    severity: Severity,
    failure_reason: str | None,
) -> GuardrailCheck:
    result = "fail" if failure_reason else "pass"
    reason = failure_reason or f"No violation detected per AGENTS.md {rule_id}"
    return GuardrailCheck(
        ruleId=rule_id,
        severity=severity,
        result=result,
        reason=reason,
    )


def _check_r1(lines: list[str]) -> str | None:
    for line in lines:
        if re.search(r"\bfrom\s+\.", line):
            return (
                f"Relative import detected: '{line.strip()}' - use absolute imports "
                "per AGENTS.md R1"
            )
    return None


def _check_r2(lines: list[str]) -> str | None:
    for line in lines:
        match = re.search(r"\b(?:os\.system\s*\(|subprocess\.)", line)
        if match:
            return (
                f"Unsafe shell call '{match.group(0)}' - requires explicit security "
                "review per AGENTS.md R2"
            )
    return None


def _check_r3(lines: list[str]) -> str | None:
    for index, line in enumerate(lines):
        if _is_public_function(line) and not _has_following_docstring(lines, index):
            return "Public function missing docstring per AGENTS.md R3"
    return None


def _is_public_function(line: str) -> bool:
    return bool(re.match(r"\s*def\s+[a-z][A-Za-z0-9]*\s*\(", line))


def _has_following_docstring(lines: list[str], index: int) -> bool:
    if index + 1 >= len(lines):
        return False
    return '"""' in lines[index + 1] or "'''" in lines[index + 1]


def _check_r4(lines: list[str]) -> str | None:
    for line in lines:
        if re.search(r"\bprint\s*\(", line):
            return "print() call detected - use efood.logging per AGENTS.md R4"
    return None


def _check_r5(lines: list[str]) -> str | None:
    for line in lines:
        match = REQUESTS_PATTERN.search(line)
        if match:
            method = match.group(1)
            return (
                f"Direct requests.{method} call - use efood.http_client "
                "per AGENTS.md R5"
            )
    return None
